-- Wipe existing route_logs and pack_outs for 2026 before inserting
DELETE FROM pack_out_logs WHERE route_log_id IN (
  SELECT id FROM route_logs WHERE log_date BETWEEN '2026-01-01' AND '2026-12-31'
);
DELETE FROM route_logs WHERE log_date BETWEEN '2026-01-01' AND '2026-12-31';


